+
+    let schema = payload
+        .get("schema")
+        .and_then(Value::as_str)
+        .unwrap_or_default();
+    if schema != OPPORTUNITY_MATRIX_SCHEMA {
+        validation_errors.push("schema_mismatch".to_string());
+    }
+
+    let source_identity = payload.get("source_identity").and_then(Value::as_object);
